import json, pathlib
ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists(): return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    for ch, verses in new_data.items():
        if ch not in existing: existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]: existing[ch][v] = html

PSALMS = {
"37": {
"1": "<p><strong>ʾal-titḥar bammĕrēʿîm ʾal-tĕqannēʾ bĕʿōśê ʿawlâ</strong> (<em>ʾal-tiṯḥar bammĕrēʿîm ʾal-tĕqannēʾ bĕʿōśê ʿawlâ</em>): 'Fret not yourself because of evildoers; be not envious of wrongdoers.' Psalm 37 is an alphabetic acrostic (each pair of verses beginning with successive Hebrew letters) attributed to David, addressing the classic theodicy problem of the prosperous wicked. The opening double prohibition — ʾal-titḥar ('do not fret') and ʾal-tĕqannēʾ ('do not be envious') — identifies the spiritual danger: not the wicked's prosperity itself but the psalmist's inner reaction to it. The verb ḥārâ ('to burn, be agitated') in the hitpael describes smoldering indignation; qānāʾ ('to be jealous, envious') describes the coveting of another's success. Both responses misread the situation.</p>",
"2": "<p><strong>kî kĕḥāṣîr mĕhērâ yibbālû ûkĕyereq dešeʾ yibbōlûn</strong> (<em>kî kĕḥāṣîr mĕhērâ yibbālû ûkĕyereq dešeʾ yibbōlûn</em>): 'For they will soon fade like the grass and wither like the green herb.' The conjunction kî ('for') provides the theological reason for not fretting: the wicked's prosperity is temporary. The two similes — kĕḥāṣîr ('like grass') and kĕyereq dešeʾ ('like the green herb/plant') — are temporal metaphors of rapid decay. The hithpalel yibbālû ('they will wither/fade') describes the irreversible process; yibbōlûn ('they will wither') is repeated for emphasis. The comparison to grass is the psalm's foundational theodicy: what appears permanent is categorically transient (cf. Ps 90:5-6; Isa 40:6-8; 1 Pet 1:24).</p>",
"3": "<p><strong>beṭaḥ baYHWH waʿăśēh ṭôb šĕkon ʾereṣ ûrĕʿēh ʾĕmûnâ</strong> (<em>ḇeṭaḥ ḇaYHWH waʿăśēh ṭôḇ šĕḵon ʾereṣ ûrĕʿēh ʾĕmûnâ</em>): 'Trust in the LORD and do good; dwell in the land and befriend faithfulness.' The psalm's positive prescriptions begin: bāṭaḥ ('trust') and ʿāśâ ṭôb ('do good') are the twin responses to the wicked's prosperity. The promise: šĕkon ʾereṣ ('dwell in the land') — the land-inheritance theme from the Abrahamic covenant (Gen 12:7; 15:7) is restated as the reward of covenant faithfulness. The phrase ûrĕʿēh ʾĕmûnâ, 'shepherd faithfulness / feed on faithfulness,' uses the verb rāʿâ ('shepherd, graze') — the psalmist is to live off divine ʾĕmûnâ as sheep graze on good pasture.</p>",
"4": "<p><strong>wĕhitʿannag ʿal-YHWH wĕyittĕn-lĕkā mišʾălôt libbĕkā</strong> (<em>wĕhiṯʿannag ʿal-YHWH wĕyittĕn-lĕḵā mišʾălôṯ libbĕḵā</em>): 'Delight yourself in the LORD, and he will give you the desires of your heart.' The hitpael wĕhitʿannag ('delight yourself') from ʿānag ('to be soft, delicate, to luxuriate') describes finding YHWH himself as one's deepest pleasure — the enjoyment of God as the supreme satisfaction. The result: wĕyittĕn-lĕkā mišʾălôt libbĕkā, 'he will give you the petitions of your heart.' The phrase is not a blank check for wish-fulfillment but a promise that when YHWH is one's delight, the heart's desires are shaped by that delight — and YHWH fulfills desires so shaped. The heart that delights in YHWH will not desire what YHWH cannot give.</p>",
"5": "<p><strong>gōl ʿal-YHWH darkekā ûbeṭaḥ ʿālāyw wĕhûʾ yaʿăśeh</strong> (<em>ḡōl ʿal-YHWH ḏarḵeḵā ûḇeṭaḥ ʿālāyw wĕhûʾ yaʿăśeh</em>): 'Commit your way to the LORD; trust in him, and he will act.' The imperative gōl ('roll!') from gālal ('to roll') — used idiomatically for rolling a burden onto another (Prov 16:3) — describes committing the entire way (derek) to YHWH: the path of one's life handed over completely. The ground: ûbeṭaḥ ʿālāyw, 'and trust in him' — trust is the posture that enables the rolling. The result: wĕhûʾ yaʿăśeh, 'and he will act' — the emphatic subject hûʾ ('he himself') emphasizes that YHWH, not the psalmist, will bring it to pass. Human commitment enables but does not produce the outcome.</p>",
"6": "<p><strong>wĕhôṣîʾ kāʾôr ṣidqekā ûmišpāṭekā katssohorayim</strong> (<em>wĕhôṣîʾ ḵāʾôr ṣiḏqeḵā ûmišpāṭeḵā katssohorayim</em>): 'He will bring forth your righteousness as the light, and your justice as the noonday.' The hiphil wĕhôṣîʾ ('he will bring forth') uses the light-emergence metaphor: righteousness that is currently hidden or obscured will be revealed. The comparison kāʾôr ('like light') and katssohorayim ('like the noonday') moves from dawn to high noon — the most brilliant, unambiguous illumination. This verse addresses the experience of the righteous person whose innocence is not recognized by the world: YHWH himself will eventually make it as visible as noon light.</p>",
"7": "<p><strong>dōm laYHWH wĕhithôlel lô ʾal-titḥar bĕmatzlîaḥ darkô</strong> (<em>ḏôm laYHWH wĕhiṯhôlel lô ʾal-tiṯḥar bĕmaṣlîaḥ darkô</em>): 'Be still before the LORD and wait patiently for him; fret not yourself over the one who prospers in his way.' The verb dōm ('be silent, still') is a rare imperative that requires active quieting — the stillness takes effort when circumstances provoke agitation. The hitpael wĕhithôlel lô ('wait in hope for him') from ḥîl ('to writhe, wait') images the taut waiting of one in labor — expectant but not yet relieved. The return of ʾal-titḥar ('fret not') from v.1 (now specifically about the one maṣlîaḥ darkô, 'who prospers in his way') shows the repeated temptation: success without apparent punishment provokes the very fretting the psalm forbids.</p>",
"8": "<p><strong>rĕpēh mēʾap wĕʿăzōb ḥēmâ ʾal-titḥar ʾak-lĕhārēaʿ</strong> (<em>rep̄ēh mēʾap wĕʿăzōḇ ḥēmâ ʾal-tiṯḥar ʾaḵ-lĕhārēaʿ</em>): 'Refrain from anger and forsake wrath! Fret not yourself; it tends only to evil.' The triple prohibition — rĕpēh ('cease!'), ʿăzōb ('abandon!'), ʾal-titḥar ('do not fret!') — demands a progressive abandonment of reactive emotions. The word ʾap ('anger, nose') and ḥēmâ ('heat, wrath') together capture both the appearance (flared nostrils) and the inner temperature of anger. The final clause ʾak-lĕhārēaʿ, 'it tends only to evil' — the fretting and anger, left to run their course, lead to evildoing. The unfretting psalmist avoids becoming what he condemns in the wicked.</p>",
"9": "<p><strong>kî mĕrēʿîm yikkārētûn wĕqōwê YHWH hēmmâ yîrĕšû ʾāreṣ</strong> (<em>kî mĕrēʿîm yikkārētûn wĕqōwê YHWH hēmmâ yîrĕšû ʾāreṣ</em>): 'For the evildoers shall be cut off, but those who wait for the LORD shall inherit the land.' The kî ('for') gives the ground for the prohibitions of vv.7-8: the outcome is secure. The verb kārat (niphal, 'be cut off') — used of covenant curses (Gen 17:14; Lev 20:17) — applies to the evildoers. But qōwê YHWH ('those who wait for the LORD') — using the taut-expectation root qāwâ — will yîrĕšû ʾāreṣ ('inherit the land'). This verse is the first of five land-inheritance promises in Psalm 37 (vv.9,11,22,29,34), which Jesus universalizes in Matt 5:5: 'Blessed are the meek, for they shall inherit the earth.'</p>",
"10": "<p><strong>wĕʿôd mĕʿaṭ wĕʾên rāšāʿ wĕhitbônanttā ʿal-mĕqōmô wĕʾênennu</strong> (<em>wĕʿôḏ mĕʿaṭ wĕʾên rāšāʿ wĕhiṯḇônantā ʿal-mĕqōmô wĕʾênennu</em>): 'In just a little while, the wicked will be no more; though you look carefully at his place, he will not be there.' The temporal phrase ʿôd mĕʿaṭ ('yet a little while') frames the wicked's dominance as imminently temporary. The verb wĕhitbônantā (hitpael, 'you will look carefully, consider attentively') describes the careful inspection of the wicked's place (maqôm) — and finding nothing. The disappearance is not merely death but trace-erasure: no evidence of the wicked's tenure remains (cf. the name-blotting of Ps 34:16). Hebrews 10:37 quotes this phrase: 'in just a little while, he who is coming will come and will not delay.'</p>",
"11": "<p><strong>waʿănāwîm yîrĕšû ʾāreṣ wĕhitʿannĕgû ʿal-rōb šālôm</strong> (<em>waʿănāwîm yîrĕšû ʾāreṣ wĕhiṯʿannĕgû ʿal-rōḇ šālôm</em>): 'But the meek shall inherit the land and delight themselves in abundant peace.' The noun ʿănāwîm ('meek, afflicted, humble') — those bent down by circumstance or by posture of humility before God — are contrasted with the rāšāʿ ('wicked'). The land inheritance yîrĕšû ʾāreṣ is their promise. The additional blessing: wĕhitʿannĕgû ʿal-rōb šālôm, 'they will delight themselves in abundant peace' — using the same hitpael of ʿānag from v.4 ('delight in the LORD'), now applied to šālôm in superabundance. Jesus quotes this verse verbatim in Matt 5:5, making the Beatitude a direct citation of the Psalter's wisdom tradition. The land promise is re-territorialized to encompass the whole earth (gē, LXX).</p>",
"12": "<p><strong>zōmēm rāšāʿ latsaddîq ûḥōrēq ʿālāyw šinnāyw</strong> (<em>zōmēm rāšāʿ latsaddîq ûḥōrēq ʿālāyw šinnāyw</em>): 'The wicked plots against the righteous and gnashes his teeth at him.' The participle zōmēm ('plotting, scheming') from zāmam ('to plan, devise') describes deliberate malice — the wicked's agenda is specifically targeted at (lĕ-) the righteous. The phrase ḥōrēq šinnāyw ('gnashing his teeth') is the bodily expression of rage and contempt, the visible sign of the wicked's inner disposition. The gnashing of teeth as a sign of judgment's approach appears in Matt 8:12; 13:42; 22:13 — the psalmist's image of the wicked's teeth-gnashing becomes, in Jesus's teaching, the eschatological condition of those who refused the kingdom.</p>",
"13": "<p><strong>ʾădōnāy yiśḥaq-lô kî rāʾâ kî yābōʾ yômô</strong> (<em>ʾăḏōnāy yiśḥaq-lô kî rāʾâ kî yāḇōʾ yômô</em>): 'But the Lord laughs at the wicked, for he sees that his day is coming.' The divine laughter — YHWH yiśḥaq ('laughs, mocks') — uses the same verb as Ps 2:4 where YHWH laughs at the nations conspiring against his anointed. The laughter is not cruelty but the expression of incomprehensible superiority: the wicked's plotting (v.12) is ludicrous from the perspective of one who sees yômô, 'his day.' The 'day' of judgment coming for the wicked makes all his scheming appear as the futile activity of someone who has already lost.</p>",
"14": "<p><strong>ḥereb pāṭĕḥû rĕšāʿîm wĕdārĕkû qaštām lĕhappîl ʿānî wĕʾebyôn</strong> (<em>ḥereḇ pāṭĕḥû rĕšāʿîm wĕḏārĕḵû qaštām lĕhappîl ʿānî wĕʾeḇyôn</em>): 'The wicked draw the sword and bend their bows to bring down the poor and needy.' The wicked's weapons — ḥereb ('sword') and qešet ('bow') — are deployed against ʿānî wĕʾebyôn ('the poor and needy'): those least able to defend themselves. The phrase lĭṭbōaḥ yišrê-derek, 'to slaughter those who walk uprightly,' adds a third target — the morally upright. The combination: the structural underdog (poor/needy) and the moral exemplar (upright) are the wicked's primary victims. Power exploits vulnerability and virtue simultaneously.</p>",
"15": "<p><strong>ḥarbām tābôʾ bĕlibbām wĕqaštôtām tišbārenâ</strong> (<em>ḥarḇām ṯāḇôʾ bĕlibbām wĕqaštôṯām tišbārenâ</em>): 'Their sword shall enter their own heart, and their bows shall be broken.' The lex talionis principle operates: ḥarbām ... bĕlibbām, 'their own sword into their own heart' — the weapon aimed at others pierces the wielder. The passive tišbārenâ ('will be broken') — the bows snapping — echoes Ps 37:17's 'arms of the wicked will be broken.' The reversal: the weapons of aggression become instruments of self-destruction. The wicked's armament, far from securing their dominance, becomes the mechanism of their defeat. This is the Psalter's consistent theology of divine poetic justice.</p>",
"16": "<p><strong>ṭôb mĕʿaṭ latsaddîq mēhāmôn rĕšāʿîm rabbîm</strong> (<em>ṭôḇ mĕʿaṭ latsaddîq mēhāmôn rĕšāʿîm rabbîm</em>): 'Better is the little that the righteous has than the abundance of many wicked.' The comparative ṭôb ... mē- ('better than') structure is the classic wisdom saying of comparative value (cf. Prov 15:16-17; 16:8). The mĕʿaṭ ('little, few') of the righteous is better than the hāmôn ('multitude, wealth, noise') of many wicked — not because poverty is virtue but because the righteous man's little is held in covenant with YHWH and therefore is genuinely satisfying, while the wicked's abundance is precarious and morally contaminated.</p>",
"17": "<p><strong>kî zĕrôʿôt rĕšāʿîm tišbārenâ wĕsômēk ṣaddîqîm YHWH</strong> (<em>kî zĕrôʿôṯ rĕšāʿîm tišbārenâ wĕsômēk ṣaddîqîm YHWH</em>): 'for the arms of the wicked shall be broken, but the LORD upholds the righteous.' The noun zĕrôʿôt ('arms') denotes power and strength — the arms of the wicked that do violence (cf. Ps 10:15) will tišbārenâ ('be broken'). The contrast: wĕsômēk ṣaddîqîm YHWH, 'but the LORD sustains/upholds the righteous.' The participle sômēk (from sāmak, 'to lean upon, support') pictures YHWH as the structural support on which the righteous lean their entire weight. The wicked support themselves by their own strength (which breaks); the righteous are upheld by YHWH (who does not break).</p>",
"18": "<p><strong>yôdēaʿ YHWH yĕmê tĕmîmîm wĕnaḥălātām lĕʿôlām tihyeh</strong> (<em>yôḏēaʿ YHWH yĕmê ṯĕmîmîm wĕnaḥălāṯām lĕʿôlām tihyeh</em>): 'The LORD knows the days of the blameless, and their heritage will abide forever.' The verb yāḏaʿ ('to know') applied by YHWH to yĕmê tĕmîmîm ('the days of the blameless') is covenantal knowledge: intimate attention and care, not merely information. The word tāmîm ('blameless, complete') — used of Noah (Gen 6:9), Abraham (Gen 17:1), and sacrificial animals without defect — describes moral integrity. The result: naḥălātām lĕʿôlām, 'their inheritance forever' — permanence opposed to the transience of the wicked (v.2).</p>",
"19": "<p><strong>lōʾ-yēbōšû bĕʿēt rāʿâ ûbîmê rĕʿābôn yiśbāʿû</strong> (<em>lōʾ-yēḇōšû bĕʿēṯ rāʿâ ûḇîmê rĕʿāḇôn yiśbāʿû</em>): 'They are not put to shame in evil times; in the days of famine they have abundance.' The promise lōʾ-yēbōšû ('they will not be ashamed/disappointed') ensures the covenant community is not humiliated even bĕʿēt rāʿâ ('in the time of evil/trouble'). The specific test: bîmê rĕʿābôn ('in days of famine') — the ultimate scarcity test — and yet yiśbāʿû ('they will be satisfied/full'). The pair shame/satisfaction frames the issue: shame is the social experience of failure; fullness is its physical opposite. The blameless will experience both social dignity and physical provision even when circumstances are worst.</p>",
"20": "<p><strong>kî rĕšāʿîm yōbēdû wĕʾōyĕbê YHWH kîqar kārîm kālû bĕʿāšān kālû</strong> (<em>kî rĕšāʿîm yōḇēḏû wĕʾōyĕḇê YHWH kîqar kārîm kālû ḇĕʿāšān kālû</em>): 'But the wicked shall perish; the enemies of the LORD are like the glory of the pastures — they vanish, like smoke they vanish away.' The antithesis: rĕšāʿîm yōbēdû ('the wicked shall perish/be destroyed') against the heritage of the blameless (v.18). The double simile: kîqar kārîm ('like the prize of the meadows / the splendor of the pastures') — momentarily beautiful — then kālû bĕʿāšān ('they vanish in smoke'). The reduplication kālû ... kālû ('they vanish ... they vanish') is emphatic: total, complete disappearance. The wicked's visible glory is the most transient thing imaginable.</p>",
"21": "<p><strong>lōweh rāšāʿ wĕlōʾ yĕšallēm wĕṣaddîq ḥônēn ûnôtēn</strong> (<em>lōweh rāšāʿ wĕlōʾ yĕšallēm wĕṣaddîq ḥônēn ûnôtēn</em>): 'The wicked borrows but does not pay back, but the righteous is generous and gives.' The economic behaviour of the two types is their moral signature: the wicked lāwâ ('borrows') but lōʾ yĕšallēm ('does not repay') — the loan becomes a theft. The righteous ḥônēn ('shows grace, is generous') and nôtēn ('gives') — without requiring repayment. The wicked's non-repayment is not merely financial irresponsibility but a moral posture of entitlement; the righteous giving is the embodiment of ḥesed in economic life. Proverbs 19:17 and Luke 6:35 elaborate the theology of generous giving without expectation of return.</p>",
"22": "<p><strong>kî mĕbōrākāyw yîrĕšû ʾāreṣ ûmĕqullālāyw yikkārētû</strong> (<em>kî mĕḇōrāḵāyw yîrĕšû ʾāreṣ ûmĕqullālāyw yikkārētû</em>): 'for those blessed by him shall inherit the land, but those cursed by him shall be cut off.' The covenant categories — blessed (bārak) and cursed (qālal) — from the Mosaic covenant (Deut 27-28) are applied: the blessed inherit the land (the Abrahamic promise renewed at Sinai) and the cursed are cut off (the covenant curse). The land-inheritance for the blessed (mĕbōrākāyw) is the fourth occurrence of this promise in the psalm (vv.9,11,22,29,34), establishing it as the psalm's central hope.</p>",
"23": "<p><strong>mēYHWH miṣʿădê-geber kônnānû wĕdarkô yeḥpāṣ</strong> (<em>mēYHWH miṣʿăḏê-ḡeḇer kônnānû wĕḏarḵô yeḥp̄āṣ</em>): 'The steps of a man are established by the LORD, when he delights in his way.' The phrase miṣʿădê-geber ('steps of a strong man') refers to each footfall in the journey of life — YHWH kônnānû ('establishes, makes firm') each step. This is divine providence applied to individual biography: not just the broad strokes of history but each step of the specific person is ordered by YHWH. The qualifier wĕdarkô yeḥpāṣ ('and he delights in his way') — YHWH's delight in the person's way is the condition: the steps of the one who delights in YHWH (v.4) are established by YHWH. The two delights are correlated.</p>",
"24": "<p><strong>kî yippōl lōʾ-yûṭal kî YHWH sômēk yādô</strong> (<em>kî yippōl lōʾ-yûṭal kî YHWH sômēk yāḏô</em>): 'though he fall, he shall not be cast headlong, for the LORD upholds his hand.' The concessive kî yippōl ('though he fall') acknowledges real failure, stumbling, and setback: the psalm is not naively optimistic. The qualification lōʾ-yûṭal ('he will not be hurled down') — from yāṭal ('to cast, throw') — distinguishes a fall that is recovered from a fatal fall. The reason: kî YHWH sômēk yādô, 'for the LORD holds his hand' — the image of a father holding a child's hand while the child stumbles, preventing a catastrophic fall. The stumbling is real; the destruction is prevented.</p>",
"25": "<p><strong>naʿar hāyîtî gam-zāqantî wĕlōʾ-rāʾîtî ṣaddîq neʾĕzāb wĕzarʿô mĕbaqqeš-lāḥem</strong> (<em>naʿar hāyîtî ḡam-zāqantî wĕlōʾ-rāʾîtî ṣaddîq neʾĕzāḇ wĕzarʿô mĕḇaqqeš-lāḥem</em>): 'I have been young, and now am old, yet I have not seen the righteous forsaken or his children begging for bread.' The personal testimony spans a lifetime: naʿar ... gam-zāqantî ('young ... and now old'). The claim wĕlōʾ-rāʾîtî ṣaddîq neʾĕzāb ('I have not seen the righteous forsaken') is empirical wisdom from lived experience — but it is also a theological claim that requires nuance: the psalmist is not denying that righteous people suffer (v.19's 'evil times') but that YHWH finally abandons them. The observation is a pattern across a long life, not a promise that every moment will be painless.</p>",
"26": "<p><strong>kol-hayyôm ḥônēn ûmalweh wĕzarʿô lĕbirākâ</strong> (<em>ḵol-hayyôm ḥônēn ûmalweh wĕzarʿô lĕḇirāḵâ</em>): 'He is ever lending generously, and his children become a blessing.' The participle ḥônēn ('showing favor, being generous') combined with malweh ('lending') describes habitual generosity: the righteous person's default economic mode is giving and lending without demanding return. The result wĕzarʿô lĕbirākâ, 'and his seed/children become a blessing,' shows the transgenerational effect: the righteous man's character shapes his children into the same pattern, and they in turn are lĕbirākâ ('for a blessing') to others (cf. Gen 12:2: Abraham 'will be a blessing').</p>",
"27": "<p><strong>sûr mērāʿ waʿăśēh-ṭôb ûšĕkon lĕʿôlām</strong> (<em>sûr mērāʿ waʿăśēh-ṭôḇ ûšĕḵon lĕʿôlām</em>): 'Turn away from evil and do good; so shall you dwell forever.' The ethical imperative returns to v.3's pattern: sûr mērāʿ ('depart from evil') + ʿāśēh ṭôb ('do good') — the pair appears also in Ps 34:14 and Isa 1:16-17 as the prophetic summary of covenant ethics. The promise: ûšĕkon lĕʿôlām, 'you will dwell forever' — the land-dwelling of v.3 extended to perpetuity. The combination of ethical instruction and land-promise reflects the covenant logic of Deuteronomy: obedience produces land-tenure; disobedience leads to exile.</p>",
"28": "<p><strong>kî YHWH ʾōhēb mišpāṭ wĕlōʾ-yaʿăzōb ʾet-ḥăsîdāyw lĕʿôlām nišmārû</strong> (<em>kî YHWH ʾōhēb mišpāṭ wĕlōʾ-yaʿăzōḇ ʾeṯ-ḥăsîḏāyw lĕʿôlām nišmārû</em>): 'For the LORD loves justice; he will not forsake his faithful ones. They are preserved forever.' The ground of covenant faithfulness: YHWH ʾōhēb mišpāṭ ('loves justice/right'). The verb ʾāhab ('love') applied to mišpāṭ means YHWH is constitutively committed to just outcomes — it is not a policy but an affection. The covenantal guarantee: wĕlōʾ-yaʿăzōb ʾet-ḥăsîdāyw ('he will not forsake his faithful ones'). The ḥăsîdîm ('covenant-loyal ones') are preserved (nišmārû) forever. The wicked children in contrast: wĕzeraʿ rĕšāʿîm nikrāt, 'the offspring of the wicked shall be cut off' — the generational reversal of v.26.</p>",
"29": "<p><strong>ṣaddîqîm yîrĕšû ʾāreṣ wĕyiškenû lāʿad ʿālêhā</strong> (<em>ṣaddîqîm yîrĕšû ʾāreṣ wĕyiškenû lāʿaḏ ʿālêhā</em>): 'The righteous shall inherit the land and dwell upon it forever.' The fifth land-inheritance promise (vv.9,11,22,29,34) is stated in its most expansive form: lāʿad ʿālêhā, 'forever upon it.' The permanence is absolute and temporal — not a temporary tenure but everlasting dwelling. The righteous (ṣaddîqîm) — defined throughout the psalm by trust, covenant-keeping, and generosity — are the true heirs of the land against which the wicked falsely claim ownership.</p>",
"30": "<p><strong>pî-ṣaddîq yehgeh ḥokmâ ûlĕšônô tĕdabbēr mišpāṭ</strong> (<em>p̄î-ṣaddîq yehgeh ḥoḵmâ ûlĕšônô ṯĕḏabbēr mišpāṭ</em>): 'The mouth of the righteous utters wisdom, and his tongue speaks justice.' The verb hāgâ ('to mutter, meditate, utter') — used in Ps 1:2 for meditating on Torah — describes the continuous output of the righteous man's mouth: wisdom (ḥokmâ) flows because Torah saturates his inner life. The parallel ûlĕšônô tĕdabbēr mišpāṭ, 'his tongue speaks justice,' connects verbal output with the courtroom: the righteous man's speech produces just outcomes in communal life. Speech and justice are inseparable in covenant ethics.</p>",
"31": "<p><strong>tôrat ʾĕlōhāyw bĕlibbô lōʾ timmāʿēd ʾăšūrāyw</strong> (<em>ṯôraṯ ʾĕlōhāyw bĕlibbô lōʾ ṯimmāʿēḏ ʾăšūrāyw</em>): 'The law of his God is in his heart; his steps do not slip.' The phrase tôrat ʾĕlōhāyw bĕlibbô ('the Torah of his God in his heart') is the Psalter's internalization motif — Torah not merely studied externally but lodged in the lēb (will-center). This is the Jeremianic 'new covenant' anticipation (Jer 31:33: 'I will put my law within them, and I will write it on their hearts') and the Deuteronomic ideal (Deut 6:6: 'these words shall be on your heart'). The consequence: lōʾ timmāʿēd ʾăšūrāyw, 'his steps do not slip/totter' — internal Torah produces external stability (cf. Ps 119:11).</p>",
"32": "<p><strong>ṣōpeh rāšāʿ latsaddîq ûmĕbaqqēš lahămîtô</strong> (<em>ṣōp̄eh rāšāʿ laṣṣaddîq ûmĕḇaqqēš lahămîtô</em>): 'The wicked watches for the righteous and seeks to put him to death.' The participle ṣōpeh ('watches, lies in wait') describes predatory surveillance — the wicked observing the righteous not with neutral attention but with lahămîtô ('to kill him') as the goal. The surveillance language connects to Ps 10:8-9 (the wicked lurking) and Ps 35:4 (seeking the psalmist's life). The righteous person lives under constant hostile observation by the wicked: their virtue provokes hatred rather than admiration.</p>",
"33": "<p><strong>YHWH lōʾ-yaʿazbennû bĕyādô wĕlōʾ yarširʿennû bĕhiššāpĕṭô</strong> (<em>YHWH lōʾ-yaʿazbennû bĕyāḏô wĕlōʾ yarširʿennû bĕhiššāp̄eṭô</em>): 'The LORD will not abandon him to his power or let him be condemned when he is brought to trial.' The divine guarantee lōʾ-yaʿazbennû ('he will not abandon him') directly addresses the wicked's lethal intention (v.32): the wicked watches to kill, but YHWH will not leave the righteous in the wicked's hand (bĕyādô). The legal protection: wĕlōʾ yarširʿennû bĕhiššāpĕṭô, 'he will not condemn him when he is judged' — the court that the wicked manipulate against the righteous (cf. Ps 35:11-12) will not produce a verdict of guilty, because YHWH is the ultimate judge.</p>",
"34": "<p><strong>qawwēh ʾel-YHWH ûšĕmōr darkô wîrômĕmĕkā lārešet ʾāreṣ bĕhikkārēt rĕšāʿîm tirʾeh</strong> (<em>qawwēh ʾel-YHWH ûšĕmōr ḏarḵô wîrômĕmeḵā lārešeṯ ʾāreṣ bĕhikkārēṯ rĕšāʿîm tirʾeh</em>): 'Wait for the LORD and keep his way, and he will exalt you to inherit the land; you will look on when the wicked are cut off.' The final land-inheritance promise: waiting on YHWH (qawwēh) combined with keeping his way (šĕmōr darkô) produces exaltation and land-tenure. The climactic vision: bĕhikkārēt rĕšāʿîm tirʾeh, 'when the wicked are cut off, you will see it' — the righteous are witnesses to the wicked's end, not victims of it. The psalm's theodicy is resolved in this witnessed reversal.</p>",
"35": "<p><strong>rāʾîtî rāšāʿ ʿārîṣ ûmiṯʿāreh kĕʾezrāḥ raʿănān</strong> (<em>rāʾîtî rāšāʿ ʿārîṣ ûmiṯʿāreh kĕʾezrāḥ raʿănān</em>): 'I have seen a wicked, ruthless man, spreading himself like a green laurel tree.' The personal testimony rāʾîtî ('I have seen') introduces an anecdote. The wicked man is ʿārîṣ ('ruthless, terrifying') — one who intimidates through power — and miṯʿāreh ('spreading himself') like a native tree (ʾezrāḥ, 'one born on the land, indigenous') that is raʿănān ('luxuriantly green'). The spreading tree is the picture of robust vitality and established dominance: the wicked man appears as well-rooted and flourishing as any tree in its native soil.</p>",
"36": "<p><strong>wayyaʿăbōr wĕhinnēh ʾênennu waʾăbaqqĕšēhû wĕlōʾ nimṣāʾ</strong> (<em>wayyaʿăḇōr wĕhinnēh ʾênennu waʾăḇaqqĕšēhû wĕlōʾ nimṣāʾ</em>): 'Then I passed by, and behold, he was no more; though I sought him, he could not be found.' The narrative suddenly shifts: wayyaʿăbōr ('and he passed by/over') and wĕhinnēh ʾênennu, 'and behold, he was not.' The conjunction wĕhinnēh ('and behold!') signals the surprise of the absence: the psalmist looked for the previously dominant wicked man — waʾăbaqqĕšēhû ('I sought him') — and found nothing. The impressive tree of v.35 has vanished. The anecdote confirms the psalm's thesis: the wicked's flourishing is as temporary as it is dramatic.</p>",
"37": "<p><strong>šĕmār tām ûrĕʾēh yāšār kî ʾaḥărît lĕʾîš šālôm</strong> (<em>šĕmār tām ûrĕʾēh yāšār kî ʾaḥărît lĕʾîš šālôm</em>): 'Mark the blameless and behold the upright, for there is a future for the man of peace.' The imperatives šĕmār ('mark, observe!') and rĕʾēh ('see!') invite contemplative attention to the tām ('blameless one') and yāšār ('upright one'). What to observe: kî ʾaḥărît lĕʾîš šālôm, 'for there is a future/end for the man of peace.' The noun ʾaḥărît ('end, latter part, future') — usually referring to the final outcome of a life — is positive for the person of šālôm. The man of integrity has a future; the wicked's 'end' is destruction (v.38). The contrast of ends reveals which life was worth living.</p>",
"38": "<p><strong>ûpōšĕʿîm nišmĕdû yaḥdāw ʾaḥărît rĕšāʿîm nikrātâ</strong> (<em>ûp̄ōšĕʿîm nišmĕdû yaḥdāw ʾaḥărît rĕšāʿîm nikrātâ</em>): 'But transgressors shall be altogether destroyed; the future of the wicked shall be cut off.' The antithesis of v.37: pōšĕʿîm ('transgressors, rebels') nišmĕdû yaḥdāw, 'are destroyed together' — collective annihilation. The ʾaḥărît rĕšāʿîm ('future/end of the wicked') is nikrātâ ('cut off') — using the same covenant-curse verb as vv.9,22,34. The contrast ʾaḥărît šālôm versus ʾaḥărît rĕšāʿîm is the psalm's sharpest theodicy: the ends of the two lives are qualitatively opposite.</p>",
"39": "<p><strong>ûtĕšûʿat ṣaddîqîm mēYHWH māʿûzzām bĕʿēt ṣārâ</strong> (<em>ûṯĕšûʿaṯ ṣaddîqîm mēYHWH māʿûzzām bĕʿēṯ ṣārâ</em>): 'The salvation of the righteous is from the LORD; he is their stronghold in the time of trouble.' The verse states explicitly what the entire psalm has assumed: the righteous do not save themselves. tĕšûʿâ ('salvation, deliverance') is mēYHWH ('from the LORD') — its source is exclusively divine. The noun māʿûz ('stronghold, refuge') from ʿāzaz ('to be strong') describes YHWH as a fortified position — the same imagery as Ps 27:1 ('the LORD is the stronghold of my life'). The 'time of trouble' (bĕʿēt ṣārâ) is when the stronghold becomes most necessary — and most evident as sufficient.</p>",
"40": "<p><strong>waYHWH yaʿăzĕrēm wayfallĕṭēm yĕfallĕṭēm mērĕšāʿîm wĕyôšîʿēm kî-ḥāsû bô</strong> (<em>waYHWH yaʿăzĕrēm wayfallĕṭēm yĕp̄allĕṭēm mērĕšāʿîm wĕyôšîʿēm kî-ḥāsû ḇô</em>): 'The LORD helps them and delivers them; he delivers them from the wicked and saves them, because they take refuge in him.' The four divine actions — yaʿăzĕrēm ('helps them'), wayfallĕṭēm ('delivers them'), yĕfallĕṭēm ('he will deliver them'), wĕyôšîʿēm ('saves them') — are the accumulated deliverances of a full psalm of trust. The final clause kî-ḥāsû bô ('because they take refuge in him') closes the psalm where it began: the foundational act of ḥāsâ-trust (v.3, bĕṭaḥ baYHWH) produces the salvation described. Trust initiates; YHWH completes. The acrostic closes with the exhaustive grammar of rescue.</p>"
},
"38": {
"1": "<p><strong>YHWH ʾal-bĕqeṣpĕkā tôkîḥēnî ûbăḥămātĕkā tĕyassĕrēnî</strong> (<em>YHWH ʾal-bĕqeṣpĕkā ṯôḵîḥēnî ûḇăḥămāṯĕḵā ṯĕyassĕrēnî</em>): 'O LORD, rebuke me not in your anger, nor discipline me in your wrath.' Psalm 38 is one of the seven penitential psalms (with Pss 6, 32, 51, 102, 130, 143) — psalms of confession and prayer for forgiveness. The opening, nearly identical to Ps 6:1, places the psalm in the tradition of prayer for divine restraint of punitive wrath. The two verbs — yākōḥ ('to rebuke, correct') and yāsar ('to discipline, chasten') — are both pedagogical: divine correction is real but potentially excessive. The psalmist does not deny deserving correction but prays that the wrath (qeṣep, ḥēmâ) be moderated: chastening, yes; annihilation, no.</p>",
"2": "<p><strong>kî ḥiṣṣêkā nēḥŝtu-bî ûtappîl ʿālay yādekā</strong> (<em>kî ḥiṣṣêḵā nēḥŝtu-ḇî ûṯappîl ʿālay yāḏeḵā</em>): 'For your arrows have sunk into me, and your hand has come down on me.' The arrows (ḥēṣ) of divine judgment — a metaphor for the painful circumstances (illness, loss) the psalmist experiences as divine response to sin — have nēḥŝtu ('sunk in, been driven'). The phrase ûtappîl ʿālay yādekā, 'and your hand presses down on me,' uses the hiphil of nāpal ('to fall, cast down') with the intensive sense of heavy pressure. YHWH's hand on the psalmist produces the physical symptoms described in vv.3-8 — the suffering is attributed to divine action, not random misfortune.</p>",
"3": "<p><strong>ʾên mĕtōm biśĕrî mippĕnê zaʿmekā ʾên šālôm baʿăṣāmay mippĕnê ḥaṭṭāʾtî</strong> (<em>ʾên mĕṯōm biśĕrî mipp̄ĕnê zaʿmeḵā ʾên šālôm baʿăṣāmay mipp̄ĕnê ḥaṭṭāʾṯî</em>): 'There is no soundness in my flesh because of your indignation; there is no health in my bones because of my sin.' The double ʾên ... ʾên ('there is no ... there is no') creates total privation: no mĕtōm ('soundness, wholeness') in the flesh (bāśār), no šālôm ('peace, health') in the bones (ʿeṣem). Both diagnoses are given double causation: mippĕnê zaʿmekā ('because of your indignation') and mippĕnê ḥaṭṭāʾtî ('because of my sin'). The psalmist refuses to separate physical suffering from theological cause: the illness is both the result of sin and the experience of divine displeasure.</p>",
"4": "<p><strong>kî ʿăwōnōtay ʿābĕrû rōʾšî kĕmaśśāʾ kābēd yikbĕdû mimmennî</strong> (<em>kî ʿăwōnōṯay ʿāḇĕrû rōʾšî kĕmaśśāʾ kāḇēḏ yiḵbĕḏû mimmennî</em>): 'For my iniquities have gone over my head; like a heavy burden, they are too heavy for me.' The spatial metaphor ʿābar rōʾš ('pass over the head') describes overwhelming: the iniquities (ʿăwōnōt) have risen above the psalmist's capacity to manage, like floodwaters that submerge. The simile kĕmaśśāʾ kābēd ('like a heavy burden') — a load heavier than the bearer — captures the crushing weight. The verb yiḵbĕdû ('they are heavy, they press') from kābēd ('to be heavy, honored') — the same root as kābôd ('glory/weight') — inverts honor: what should be light (forgiven sin) becomes crushing (unforgiven guilt).</p>",
"5": "<p><strong>hibʾîšû nāmaqû ḥabbûrōtāy mippĕnê ʾiwwaltî</strong> (<em>hiḇʾîšû nāmaqû ḥabbûrôṯāy mipp̄ĕnê ʾiwwaltî</em>): 'My wounds stink and fester because of my foolishness.' The verb bāʾaš ('to stink, be offensive') in the hiphil hiḇʾîšû ('they have made to stink') — combined with nāmaqû ('they are putrid, have rotted') — describes infected wounds whose stench signals advanced corruption. The word ḥabbûrôt ('wounds, bruises, stripes') are the physical marks; mippĕnê ʾiwwaltî, 'because of my foolishness,' names the source. The noun ʾiwwelet ('foolishness') in Proverbs is the opposite of ḥokmâ ('wisdom') — the fool acts without regard for consequences or covenant, and the festering wounds are the embodied consequence.</p>",
"6": "<p><strong>naʿăwêtî šaḥōtî ʿad-mĕʾōd kol-hayyôm qōdēr hibbāltî</strong> (<em>naʿăwêṯî šaḥōṯî ʿaḏ-mĕʾōḏ ḵol-hayyôm qōḏēr hibbālṯî</em>): 'I am utterly bowed down and prostrate; all the day I go about mourning.' The verb ʿāwâ (niphal naʿăwêtî, 'I am bowed, twisted, bent over') captures the physical posture of someone whose weight of suffering prevents standing erect. The intensifiers — šāḥôtî ʿad-mĕʾōd ('bowed down exceedingly') — amplify. The temporal phrase kol-hayyôm ('all the day') eliminates any interval of relief. The participle qōdēr ('darkened, in dark mourning garments') describes the public appearance of grief: the psalmist walks about visibly in mourning, unable to conceal his state.</p>",
"7": "<p><strong>kî ḵeślay mālĕʾû niqeh ûʾên mĕtōm biśĕrî</strong> (<em>kî ḵeślay māleʾû niqeh ûʾên mĕṯōm biśĕrî</em>): 'For my loins are filled with burning, and there is no soundness in my flesh.' The noun kesālayim ('loins, the lumbar/kidney region') and the verbal niqeh (from nilqad or related — 'burning, inflammation') describe severe internal pain. The repeated ʾên mĕtōm biśĕrî ('no soundness in my flesh') from v.3 — the inclusio of bodily suffering — underscores that the illness is total: no part of the body has escaped the divine correction. The psalmist's entire physical being is the medium of penitential experience.</p>",
"8": "<p><strong>pûgôtî wĕnidkêtî ʿad-mĕʾōd šāʾagtî minnehămat libbî</strong> (<em>p̄ûḡôṯî wĕniḏkêṯî ʿaḏ-mĕʾōḏ šāʾaḡtî minnehămaṯ libbî</em>): 'I am feeble and crushed; I groan because of the tumult of my heart.' The verb pûg ('to be numb, feeble, exhausted') combined with dākkâ (niphal niḏkêṯî, 'I am crushed, pulverized') — the same root as dakkāʾ in Ps 34:18 ('crushed in spirit') — describe the inner dissolution of one who has reached physical and emotional exhaustion. The audible response: šāʾagtî ('I roar, groan') minnehămat libbî, 'because of the agitation/turmoil of my heart.' The lion-roar šāʾag applied to human anguish conveys the involuntary, raw vocalisation of extreme distress — what Hezekiah's prayer in Isa 38:14 calls 'chattering like a swallow.'</p>",
"9": "<p><strong>ʾădōnāy nĕgdĕkā kol-taʾăwātî wĕʾanḥātî mimmĕkā lōʾ-nistārâ</strong> (<em>ʾăḏōnāy neḡḏeḵā ḵol-taʾăwāṯî wĕʾanḥāṯî mimmĕḵā lōʾ-nistārâ</em>): 'O Lord, all my longing is before you; my sighing is not hidden from you.' The divine address ʾădōnāy ('my Lord') in direct speech — after the third-person description of suffering — personalizes the prayer. The phrase nĕgdĕkā kol-taʾăwātî, 'before you is all my longing,' uses neged ('in front of, before') to assert that YHWH sees the psalmist's deepest desire. The groaning (ʾanḥâ) that the heart produces (v.8) is lōʾ-nistārâ ('not hidden') from YHWH — nothing is concealed. The reassurance: even the inarticulate suffering of v.8 reaches God as fully as any formulated prayer.</p>",
"10": "<p><strong>libbî sĕḥar koḥî ʿăzābānî wĕʾôr-ʿênay gam-hēm ʾên ʾittî</strong> (<em>libbî sĕḥar ḵōḥî ʿăzāḇānî wĕʾôr-ʿênay ḡam-hēm ʾên ʾittî</em>): 'My heart throbs; my strength fails me, and the light of my eyes — it also has gone from me.' The verb sāḥar (here 'throb, race') describes the heart's physical distress — palpitations from illness or anxiety. The phrase kōḥî ʿăzābānî ('my strength has abandoned me') uses ʿāzab ('to leave, forsake') — the same verb used of YHWH's forsaking in Ps 22:1. Physical exhaustion is framed as abandonment. The most poignant element: wĕʾôr-ʿênay gam-hēm ʾên ʾittî, 'even the light of my eyes has left me' — the eyes that once saw light are darkened. Complete sensory and physical failure accompanies the spiritual crisis.</p>",
"11": "<p><strong>ʾōhăbay wĕrēʿay minneged negʿî yaʿamōdû ûqĕrôbay mērāḥōq ʿāmādû</strong> (<em>ʾōhăḇay wĕrēʿay minnegeḏ negʿî yaʿămōḏû ûqĕrôḇay mērāḥôq ʿāmāḏû</em>): 'My friends and companions stand aloof from my plague, and my nearest kin stand far off.' The social dimension of suffering: ʾōhăbay ('my lovers, those who love me'), rēʿay ('my companions'), and qĕrôbay ('my near ones, relatives') all maintain distance. The phrase minneged negʿî ('from the presence of my plague') — the wound/disease is the reason for their withdrawal — suggests that the psalmist's suffering is visible and repulsive. The spatial opposites yaʿamōdû ('they stand') and mērāḥōq ('at a distance') echo the social abandonment motif of Ps 22:11 and the suffering servant's social isolation in Isa 53:3. The abandonment by intimates is a recognizable form of human suffering that Jesus also experienced (Mark 14:50).</p>",
"12": "<p><strong>waynĕqĕšû mĕbaqqĕšê napšî wĕdōrĕšê rāʿātî dibbĕrû hawwôt</strong> (<em>waynĕqĕšû mĕḇaqqĕšê napšî wĕḏōrĕšê rāʿāṯî dibbĕrû hawwôṯ</em>): 'Those who seek my life lay their snares; those who seek my hurt speak of ruin and meditate treachery all the day long.' The contrast to the distant friends (v.11): the enemies are actively engaged. mĕbaqqĕšê napšî ('those who seek my life') lay traps (nāqaš, 'to snare'); dōrĕšê rāʿātî ('those who seek my harm') speak hawwôt ('ruination, disaster'). The phrase ûmirmôt kol-hayyôm yehgû, 'and meditate deceit all the day,' uses hāgâ from Ps 1:2 — the daily meditation on Torah inverted into daily scheming of deceit. What the righteous meditates on (Torah) determines character; what the wicked meditates on (mirmâ) determines destruction.</p>",
"13": "<p><strong>waʾănî kĕḥērēš lōʾ ʾĕšmaʿ ûkĕ'illēm lōʾ yiptaḥ pîw</strong> (<em>waʾănî ḵĕḥērēš lōʾ ʾĕšmaʿ ûḵĕ'illēm lōʾ yip̄taḥ pîw</em>): 'But I am like a deaf man; I do not hear, like a mute man who does not open his mouth.' The waw-adversative waʾănî ('but I') introduces the psalmist's chosen response to the enemies: silence. The similes kĕḥērēš ('like a deaf one') and kĕ'illēm ('like a mute one') describe a deliberate non-engagement. The psalmist neither hears the enemy's slanders nor responds to them — a profound counterintuitive strategy. Isaiah 53:7 applies a nearly identical posture to the Servant: 'like a sheep that before its shearers is silent, so he opened not his mouth.' Matthew 26:63 and 27:14 note that Jesus was silent before his accusers, fulfilling this prophetic-psalmist pattern.</p>",
"14": "<p><strong>waʾĕhî kĕʾîš ʾăšer lōʾ šômēaʿ ûʾên bĕpîw tôkāḥôt</strong> (<em>waʾĕhî ḵĕʾîš ʾăšer lōʾ šômēaʿ ûʾên bĕp̄îw tôḵāḥôṯ</em>): 'So I have become like a man who does not hear, and in whose mouth are no rebukes.' The continuation of v.13: the psalmist's silence extends to the absence of tôkāḥôt ('rebukes, counter-arguments') in his mouth. The word tôkāḥat is the technical term for the reasoned argument in a legal dispute — the psalmist has no counter-charges, no legal defense, no retaliatory rebuke. This absolute silence before accusation is one of the most remarkable postures in the Psalter. The choice to be silent rather than self-defend reflects trust in YHWH as the true advocate (cf. v.15).</p>",
"15": "<p><strong>kî-lĕkā YHWH hôḥāltî ʾattâ taʿăneh ʾădōnāy ʾĕlōhāy</strong> (<em>kî-lĕḵā YHWH hôḥāltî ʾattâ taʿăneh ʾăḏōnāy ʾĕlōhāy</em>): 'For it is for you, O LORD, that I wait; it is you, O Lord my God, who will answer.' The silence of vv.13-14 is explained here: the psalmist is silent before humans kî ('because') he waits for YHWH to answer. The verb yāḥal (hophal hôḥāltî, 'I wait with hope') from ḥil ('to writhe, wait in tense expectation') indicates patient but urgent hope. YHWH himself — ʾattâ taʿăneh ('you will answer') — is the one who speaks in the courtroom where humans have heard only silence. The logic: be silent before false accusers; wait for the True Judge to answer.</p>",
"16": "<p><strong>kî-ʾāmartî pen-yiśmĕḥû-lî bĕmôṭ raglî ʿālay higdîlû</strong> (<em>kî-ʾāmartî pen-yiśmĕḥû-lî bĕmôṭ raglî ʿālay higdîlû</em>): 'For I said, 'Only let them not rejoice over me, who boast against me when my foot slips!'' The internal monologue kî-ʾāmartî ('for I said') reveals the psalmist's specific fear: pen-yiśmĕḥû-lî ('lest they rejoice at my expense'). The condition bĕmôṭ raglî ('when my foot slips') — the very stumbling that Ps 37:24 promises YHWH prevents — is here the feared occasion for enemy gloating. The phrase ʿālay higdîlû, 'they magnify themselves against me,' describes arrogant self-assertion at the psalmist's expense. The prayer for non-shame (cf. Pss 25:2; 35:19) underlies the entire penitential complex.</p>",
"17": "<p><strong>kî-ʾănî lĕṣelaʿ nākôn ûmaʿkōbî negdî tāmîd</strong> (<em>kî-ʾănî lĕṣelaʿ nāḵôn ûmaʿkōḇî neḡḏî ṯāmîd</em>): 'For I am ready to fall, and my pain is ever before me.' The phrase lĕṣelaʿ nākôn ('prepared for limping/stumbling') — the participial nākôn ('prepared, established') with ṣelaʿ ('limping, stumbling') — describes permanent precariousness: the psalmist is perpetually on the verge of collapse, one more failure away from falling. The phrase ûmaʿkōbî negdî tāmîd, 'and my pain is ever before me,' means the suffering is never out of sight: it is the constant foreground of experience, not the background. The word maʿkōb ('pain, anguish') appears in Isaiah 53:3 as the Servant's defining experience: 'a man of sorrows and acquainted with grief.'</p>",
"18": "<p><strong>kî-ʿăwōnî ʾaggîd ʾeddĕʾag mēḥaṭṭāʾtî</strong> (<em>kî-ʿăwōnî ʾaggîd ʾeddĕʾag mēḥaṭṭāʾtî</em>): 'For I confess my iniquity; I am sorry for my sin.' The decisive turn: the psalmist moves from describing suffering to explicit confession. The verb nāgad (hiphil ʾaggîd, 'I will declare, confess') marks the public acknowledgment of ʿăwōnî ('my iniquity'). The parallel ʾeddĕʾag mēḥaṭṭāʾtî, 'I am sorry/troubled because of my sin,' uses the verb dāʾag ('to be anxious, worried, sorrowful') — not mere intellectual acknowledgment but emotional distress over the sin itself. This is the movement of genuine repentance: from suffering → recognition of sin's role → active confession → sorrow. The penitential psalm reaches its theological core.</p>",
"19": "<p><strong>wĕʾōyĕbay ḥayyîm ʿāṣēmû wĕrabbû śōnĕʾay šeqer</strong> (<em>wĕʾōyĕḇay ḥayyîm ʿāṣēmû wĕrabbû śōnĕʾay šeqer</em>): 'But my enemies are vigorous and many, and those who hate me wrongfully have multiplied.' The contrast: the psalmist is diminished (vv.3-10), but the enemies are ḥayyîm ʿāṣēmû ('lively, vigorous and strong'). Their number has rabbû ('multiplied') — a qualitative increase in opposition. The phrase śōnĕʾay šeqer ('those who hate me falsely/without cause') returns to the Psalter's recurring motif of unprovoked enmity (cf. Ps 35:19; 69:4 — both cited in John 15:25 for the world's hatred of Jesus).</p>",
"20": "<p><strong>wĕmĕšallĕmê rāʿâ taḥat ṭôbâ yiśṭĕnûnî taḥat rŏdpî-ṭôb</strong> (<em>wĕmĕšallĕmê rāʿâ taḥaṯ ṭôḇâ yiśṭĕnûnî ṯaḥaṯ rŏḏpî-ṭôḇ</em>): 'Those who render evil for good accuse me because I follow after good.' The specific charge against the psalmist: mĕšallĕmê rāʿâ taḥat ṭôbâ ('those who repay evil for good') — the same moral inversion as Ps 35:12. The word śāṭan ('to be an adversary, to accuse') appears here in verbal form: yiśṭĕnûnî, 'they act as adversaries against me / they accuse me.' The ground of their accusation: taḥat rŏdpî-ṭôb, 'because I pursue good.' Goodness is the provocation: the wicked cannot tolerate virtue in others because it judges them by contrast.</p>",
"21": "<p><strong>ʾal-taʿazbēnî YHWH ʾĕlōhay ʾal-tirḥaq mimmennî</strong> (<em>ʾal-taʿazbēnî YHWH ʾĕlōhay ʾal-tirḥaq mimmennî</em>): 'Do not forsake me, O LORD! O my God, be not far from me!' The negative imperatives ʾal-taʿazbēnî ('do not forsake me!') and ʾal-tirḥaq ('do not be far!') are the central petition after the long confession and description of suffering. The prayer against divine abandonment (ʿāzab) picks up the physical abandonment of strength (v.10, kōḥî ʿăzābānî) — even the psalmist's own strength has forsaken him; now he prays YHWH will not do the same. The spatial nearness ʾal-tirḥaq echoes Ps 22:11 and Ps 35:22 — the same prayer in the darkest moments of the Psalter.</p>",
"22": "<p><strong>ḥûšâ lĕʿezrātî ʾădōnāy tĕšûʿātî</strong> (<em>ḥûšâ lĕʿezrātî ʾăḏōnāy tĕšûʿāṯî</em>): 'Make haste to help me, O Lord, my salvation!' The urgent final petition ḥûšâ ('hurry!') from ḥûš ('to move quickly, hasten') adds temporal urgency: help is needed now. The address ʾădōnāy with the possessive tĕšûʿātî ('my salvation') makes YHWH personally the psalmist's yešûʿâ — salvation personified. The brief ending stands in sharp contrast to the extended suffering of vv.1-20: the long description of distress yields to a two-element prayer — come to my help quickly, you who are my salvation. The compression is itself a form of trust: the psalmist reduces everything to the one thing needed.</p>"
},
"39": {
"1": "<p><strong>ʾāmartî ʾeśmĕrâ dĕrākay mēḥăṭōʾ bilĕšônî ʾeśmĕrâ lĕpî mazzōm</strong> (<em>ʾāmartî ʾeśmĕrâ ḏĕrāḵay mēḥăṭōʾ ḇilĕšônî ʾeśmĕrâ lĕp̄î mazzōm</em>): 'I said, 'I will guard my ways, that I may not sin with my tongue; I will guard my mouth with a muzzle.'' Psalm 39 is attributed to David with a dedication to Jeduthun, one of the chief temple musicians (1 Chr 16:41-42). The opening resolve — ʾeśmĕrâ ('I will guard') applied to both darkay ('my ways') and pî ('my mouth') — describes the determined self-restraint of someone who has learned that careless speech about God's governance leads to sin. The noun mazzôm (or miśmôr, 'muzzle, bridle') is uniquely striking: the mouth is to be as controlled as a bridled horse. The reason: bĕʿôd rāšāʿ lĕnegdî, 'while the wicked are in my presence' — the psalmist restrains speech about divine justice in the hearing of the ungodly, lest his complaint be ammunition for their atheism.</p>",
"2": "<p><strong>neʾĕlamtî dûmiyyâ heḥĕšêtî mîṭṭôb ûmaʿkōbî neʿkār</strong> (<em>neʾĕlamtî ḏûmiyyâ heḥĕšêtî mîṭṭôb ûmaʿkōḇî neʿkār</em>): 'I was mute and silent; I held my peace to no avail, and my distress grew worse.' The three verbs of silence — neʾĕlamtî ('I was made mute'), dûmiyyâ ('I was still/silent'), heḥĕšêtî ('I kept quiet') — escalate: silence was attempted at every level. The phrase mîṭṭôb ('from good') suggests the silence extended even to good things — he held back not just complaints but anything. The result: ûmaʿkōbî neʿkār, 'and my pain was stirred/increased.' The silence that was meant to manage distress instead intensified it: suppressed anguish becomes more acute. The psalm's opening explains why speech eventually erupts (v.3).</p>",
"3": "<p><strong>ḥam-libbî bĕqirbî bĕhaggîgî tîbʿar-ʾēš dibbartî billĕšônî</strong> (<em>ḥam-libbî bĕqirḇî bĕhaggîgî ṯîḇʿar-ʾēš dibbartî ḇillĕšônî</em>): 'My heart became hot within me. As I mused, the fire burned; then I spoke with my tongue.' The heart's heat — ḥam-libbî ('my heart became hot') — describes suppressed anguish building to overflow. The verb hāgâ (bĕhaggîgî, 'as I mused/meditated') is the meditation root of Ps 1:2 — but here meditation intensifies rather than calms: tîbʿar-ʾēš, 'the fire burned.' Fire is the image of contained energy suddenly beyond control: the discipline of vv.1-2 fails, and dibbartî billĕšônî ('I spoke with my tongue') — the resolution breaks. The psalmist speaks — and what he speaks is the meditation on mortality in vv.4-6.</p>",
"4": "<p><strong>hôdîʿēnî YHWH qiṣṣî ûmiddat yāmay mah-hîʾ ʾēdĕʿâ meh-ḥādēl ʾānî</strong> (<em>hôḏîʿēnî YHWH qiṣṣî ûmiḏḏaṯ yāmay mah-hîʾ ʾēḏĕʿâ meh-ḥāḏēl ʾānî</em>): 'O LORD, make me know my end and what is the measure of my days; let me know how fleeting I am!' The prayer for self-knowledge hôdîʿēnî ('make me know!') is unusual: the psalmist asks YHWH to reveal his mortality — qiṣṣî ('my end'), middat yāmay ('the measure of my days'). The phrase meh-ḥādēl ʾānî, 'how transient/failing I am,' uses ḥādal ('to cease, fail, stop') — the psalmist as someone who will simply stop. The prayer for mortality-awareness is not morbid self-pity but a request for the theological insight that Ps 90:12 calls wisdom: 'teach us to number our days.'</p>",
"5": "<p><strong>hinnēh ṭĕpāḥôt nātattâ yāmay wĕḥeldî kĕʾayin nĕgdekā</strong> (<em>hinnēh ṭĕp̄āḥôṯ nāṯattâ yāmay wĕḥeldî kĕʾayin neḡḏeḵā</em>): 'Behold, you have made my days a few handbreadths, and my lifetime is as nothing before you. Surely all mankind stands as a mere breath!' The handbreadth (ṭepaḥ) — roughly 3 inches, the smallest unit of measurement — reduces the span of a life to a trivial interval. The phrase wĕḥeldî kĕʾayin nĕgdekā, 'my lifespan is as nothing before you,' uses the comparison to divine eternity: sub specie aeternitatis, any human life is negligible in duration. The conclusion: ʾak kol-hebel kol-ʾādām niṣṣāb selah, 'surely every man standing is but breath.' The word hebel ('breath, vapor, vanity') — the central term of Ecclesiastes — makes human existence as transient as an exhaled breath. The Selah invites meditation on the weight of this reality.</p>",
"6": "<p><strong>ʾak bĕṣelem yithallak-ʾîš ʾak-hebel yehĕmāyûn yiṣbōr wĕlōʾ-yēdaʿ mî-yōsĕpēm</strong> (<em>ʾaḵ bĕṣelem yiṯhallak-ʾîš ʾaḵ-heḇel yehĕmāyûn yiṣḇōr wĕlōʾ-yēḏaʿ mî-yōsĕp̄ēm</em>): 'Surely a man goes about like a shadow! Surely for nothing they are in turmoil; man heaps up wealth and does not know who will gather.' The phrase bĕṣelem yithallak-ʾîš ('a man goes about like a shadow/image') uses ṣelem ('image, shadow') — the same word as 'image of God' (bĕṣelem ʾĕlōhîm, Gen 1:26-27) — here ironically: humanity made in the image is itself a shadow. The turmoil of wealth-accumulation: yiṣbōr wĕlōʾ-yēdaʿ mî-yōsĕpēm, 'he piles up and does not know who will gather it.' Jesus's parable of the rich fool (Luke 12:16-21) directly engages this wisdom.</p>",
"7": "<p><strong>wĕʿattâ mah-qiwwîtî ʾădōnāy tôḥaltî lĕkā hîʾ</strong> (<em>wĕʿattâ mah-qiwwîtî ʾăḏōnāy tôḥaltî lĕḵā hîʾ</em>): 'And now, O Lord, for what do I wait? My hope is in you.' The transitional wĕʿattâ ('and now') marks the pivot from the meditation on mortality (vv.4-6) to its theological conclusion: if human life is hebel and human wealth is uncertain, what can the psalmist wait for? The answer: tôḥaltî lĕkā hîʾ ('my hope is in you — it is you'). The emphatic hîʾ ('it is') makes YHWH the exclusive content of hope: not health, not prosperity, not longevity — YHWH himself. The tôḥalt root (from yāḥal, 'wait/hope') identifies the type of hope: taut, expectant, rope-like — a hope that pulls toward its object.</p>",
"8": "<p><strong>mikkol-pĕšāʿay haṣṣîlēnî ḥerpat nābāl ʾal-tĕśîmēnî</strong> (<em>mikḵol-p̄ĕšāʿay haṣṣîlēnî ḥerpat nāḇāl ʾal-tĕśîmēnî</em>): 'Deliver me from all my transgressions. Do not make me the scorn of the fool!' The two petitions: haṣṣîlēnî ('deliver me') from pĕšāʿay ('my transgressions/rebellions') — deliverance from sin's consequences. And: ʾal-tĕśîmēnî ḥerpat nābāl, 'do not make me an object of reproach for the fool' — the nābāl ('moral fool' of Ps 14:1) who denies God's governance would use the psalmist's suffering as evidence that righteousness does not pay. The prayer against becoming fodder for practical atheism joins personal deliverance to theological witness.</p>",
"9": "<p><strong>neʾĕlamtî lōʾ ʾeptaḥ pî kî ʾattâ ʿāśîtā</strong> (<em>neʾĕlamtî lōʾ ʾep̄taḥ pî kî ʾattâ ʿāśîṯā</em>): 'I am mute; I do not open my mouth, for it is you who have done it.' The silence of vv.1-2 returns: neʾĕlamtî lōʾ ʾeptaḥ pî ('I am mute, I do not open my mouth'). But now the reason is given: kî ʾattâ ʿāśîtā, 'for you have done it.' The suffering is acknowledged as divine action — the same theology as Ps 38:2-3 but now stated simply and without accusation. The psalmist does not complain to others about what God has done; silence before humans is the response to the recognition that divine sovereignty governs all that happens. This is the silent submission of Job 1:21 ('the LORD gave, the LORD has taken away; blessed be the name of the LORD').</p>",
"10": "<p><strong>hāsēr mēʿālay nigʿekā mittignûrat yādĕkā ʾănî kālîtî</strong> (<em>hāsēr mēʿālay niḡʿeḵā mittignûraṯ yāḏĕḵā ʾănî ḵālîṯî</em>): 'Remove your stroke from me; I am spent by the hostility of your hand.' The imperative hāsēr ('remove, turn away!') from sûr applied to nigʿekā ('your blow/stroke') — the divine affliction of v.2 that is experienced as YHWH's hand. The phrase mittignûrat yādĕkā ('from the hostility/contention of your hand') — tigra' may mean 'blow/combat/opposition' — pictures the divine hand pressing down. The result: ʾănî kālîtî, 'I am spent/consumed' — from kālâ ('to be finished, consumed'). The psalmist is at the limit of his capacity to bear the divine correction.</p>",
"11": "<p><strong>bĕtôkāḥôt ʿal-ʿāwōn yissartā ʾîš wattemes kaʿāš ḥămûdô ʾak hebel kol-hāʾādām selah</strong> (<em>bĕṯôḵāḥôṯ ʿal-ʿāwōn yissartā ʾîš wattemes kaʿāš ḥămûdô ʾaḵ heḇel ḵol-hāʾāḏām selah</em>): 'When you discipline a man with rebukes for sin, you consume like a moth what is dear to him; surely all mankind is a mere breath!' The metaphor of moth consumption — kāʿāš ḥămûdô ('like a moth, what is dear to him') — images the silent, invisible destruction of what is most precious: the moth consumes from within, leaving the outward form intact but the substance eaten away. Divine discipline for sin operates similarly: gradually consuming the things one holds dear. The Selah again punctuates the conclusion ʾak hebel kol-hāʾādām, 'surely all humanity is a breath' — reinforcing the transience established in v.5.</p>",
"12": "<p><strong>šimʿâ tĕpillātî YHWH wĕšawʿātî haʾăzînâ ʾel-dimʿātî ʾal-teḥeraš</strong> (<em>šimʿâ ṯĕp̄illāṯî YHWH wĕšawʿāṯî haʾăzînâ ʾel-dimʿāṯî ʾal-teḥeraš</em>): 'Hear my prayer, O LORD, and give ear to my cry; hold not your peace at my tears.' The petition summons three divine senses: hearing for the prayer (tĕpillâ), attentive listening for the cry (šawʿâ), and responding to the tears (dimʿâ). The phrase ʾal-teḥeraš ('do not be silent!') makes the tears themselves a form of prayer — even inarticulate weeping demands divine response. The theological ground: kî gēr ʾānōkî ʿimmĕkā tôšāb kĕkol-ʾăbōtāy, 'for I am a sojourner with you, a guest, as all my fathers were.' The psalmist's identity as a gēr ('sojourner, alien') before YHWH provides the basis for his appeal — sojourners depend entirely on their host's hospitality (cf. Heb 11:13: 'strangers and pilgrims on the earth').</p>",
"13": "<p><strong>hāšaʿ mimmennî wĕʾabligâ bĕṭerem ʾēlēk wĕʾênennî</strong> (<em>hāšaʿ mimmennî wĕʾaḇliḡâ ḇĕṭerem ʾēlēk wĕʾênennî</em>): 'Look away from me, that I may smile again, before I depart and am no more!' The closing request is striking: hāšaʿ mimmennî ('look away from me!') — previously the psalmist prayed for God to look at him (v.12); now he prays for divine gaze to relent. The divine attention has been experienced as the source of his affliction (v.10-11); a momentary lifting of that gaze would allow recovery. The purpose wĕʾabligâ ('that I might brighten/recover a smile') from bālag ('to smile, brighten') — even a brief respite before the end. The phrase bĕṭerem ʾēlēk wĕʾênennî, 'before I go and am no more,' is the psalm's most poignant phrase — the awareness of mortality pressing close. The psalm ends not with resolution but with the raw prayer of one who expects death soon and wants a moment's relief before it comes.</p>"
},
"40": {
"1": "<p><strong>qawwōh qiwwîtî YHWH wayyēṭ ʾēlay wayyišmaʿ šawʿātî</strong> (<em>qawwōh qiwwîtî YHWH wayyēṭ ʾēlay wayyišmaʿ šawʿātî</em>): 'I waited patiently for the LORD; he inclined to me and heard my cry.' The cognate infinitive absolute qawwōh qiwwîtî ('I waited, waited!') is intensified repetition — the waiting was sustained, thorough, emphatic. This is the taut expectation of qāwâ ('to hope with expectation'), not passive resignation. The divine response: wayyēṭ ʾēlay ('he inclined toward me') — the anthropomorphism of a king bending to hear a petition — and wayyišmaʿ šawʿātî ('he heard my cry'). The psalm opens with answered prayer and works backward and forward from this center of rescue.</p>",
"2": "<p><strong>wayyaʿălēnî mibbôr šāʾôn mîṭîṭ hayyāwēn wayyāqem ʿal-selaʿ raglāy kônnēn ʾăšûrāy</strong> (<em>wayyaʿălēnî mibbôr šāʾôn mîṭîṭ hayyāwēn wayyāqem ʿal-selaʿ raglāy ḵônnēn ʾăšûrāy</em>): 'He drew me up from the pit of destruction, out of the miry bog, and set my feet upon a rock, making my steps secure.' The spatial rescue from bôr šāʾôn ('the pit of roaring/destruction') and ṭîṭ hayyāwēn ('the miry clay') to selaʿ ('a rock') is the psalm's central metaphor: from chaotic instability to stable ground. The word bôr ('pit') is used for the grave/Sheol in Ps 28:1; 30:3 — the rescue is from the edge of death. The rock (selaʿ) appears throughout the Psalter as the divine attribute of stability (Ps 18:2, 31); here it is the literal place where the delivered one stands.</p>",
"3": "<p><strong>wayyittēn bĕpî šîr ḥādāš tĕhillâ lēʾlōhênû yirʾû rabbîm wĕyîrāʾû wĕyibṭĕḥû baYHWH</strong> (<em>wayyittēn bĕp̄î šîr ḥādāš ṯĕhillâ lēʾlōhênû yirʾû rabbîm wĕyîrāʾû wĕyiḇṭĕḥû ḇaYHWH</em>): 'He put a new song in my mouth, a song of praise to our God. Many will see and fear, and put their trust in the LORD.' The divine gift of šîr ḥādāš ('a new song') — the song that rescue produces is qualitatively new: it cannot be the old song because the situation is transformed. The phrase wayyittēn bĕpî ('he placed in my mouth') makes the song a divine endowment, not self-generated praise. The missionary effect: yirʾû rabbîm ('many will see') → wĕyîrāʾû ('they will fear') → wĕyibṭĕḥû baYHWH ('they will trust in the LORD'). Rescue generates testimony which generates fear of God which generates trust: a chain of effect from one person's deliverance to the expansion of the covenant community.</p>",
"4": "<p><strong>ʾašrê haggeber ʾăšer śām YHWH miṭlaḥtô wĕlōʾ-pānâ ʾel-rĕhābîm wĕśāṭê kāzāb</strong> (<em>ʾašrê haggeber ʾăšer śām YHWH miṭlaḥtô wĕlōʾ-p̄ānâ ʾel-rĕhābîm wĕśāṭê ḵāzāb</em>): 'Blessed is the man who makes the LORD his trust, who does not turn to the proud, to those who go astray after a lie!' The beatitude ʾašrê ('blessed!') marks the transition from personal testimony to universal instruction. The one who makes YHWH miṭlaḥtô ('his trust') — the object of utter reliance — is blessed. The negative contrasts: lōʾ-pānâ ('he does not turn') toward rĕhābîm ('the proud, arrogant') or śāṭê kāzāb ('those who go off after a lie'). The lie is the false alternative to YHWH — any competing object of trust that promises what only YHWH can give.</p>",
"5": "<p><strong>rabbôt ʿāśîtā ʾattâ YHWH ʾĕlōhay niplĕʾōtêkā wĕmaḥšĕbōtêkā ʾēlênû</strong> (<em>rabbôṯ ʿāśîṯā ʾattâ YHWH ʾĕlōhay niplĕʾōṯeḵā wĕmaḥšĕḇōṯeḵā ʾēlênû</em>): 'You have multiplied, O LORD my God, your wondrous deeds and your thoughts toward us; none can compare with you!' The declaration rabbôt ʿāśîtā ('you have done many things') introduces the theme of divine abundance: the niplĕʾôt ('wonders, marvelous deeds') and maḥšĕbôt ('thoughts, plans') toward ʾêlênû ('us') are countless. The phrase ʾên-ʿārak ʾēlêkā ('none can compare to you') is the incomparability formula — YHWH's acts are without analogue. The attempt to declare them: ʾaggîdâ wădabbĕrâ ʿāṣĕmû missappēr ('if I would declare and speak of them, they are too many to count') — the exhaustion of language before divine abundance.</p>",
"6": "<p><strong>zebaḥ ûminḥâ lōʾ-ḥāpaṣtā ʾoznayim kārîtā lî ʿōlâ waḥăṭāʾâ lōʾ šāʾāltā</strong> (<em>zeḇaḥ ûminḥâ lōʾ-ḥāp̄aṣtā ʾoznayim kārîtā lî ʿōlâ waḥăṭāʾâ lōʾ šāʾāltā</em>): 'In sacrifice and offering you have not delighted; ears you have dug for me; burnt offering and sin offering you have not required.' The declaration that YHWH does not ḥāpaṣ ('delight in') the four sacrifice types — zebaḥ (peace offering), minḥâ (grain offering), ʿōlâ (burnt offering), ḥaṭāʾâ (sin offering) — is prophetically radical, echoing Isa 1:11; Amos 5:21-22; Mic 6:6-8. The remarkable alternative: ʾoznayim kārîtā lî, 'ears you have dug for me' (MT) — possibly meaning 'you have created me as one who hears/obeys.' The LXX reads instead 'a body you have prepared for me' (sōma katērtisō moi), and Hebrews 10:5-7 quotes the LXX version, applying it to the incarnation: Christ's body is the true offering that replaces animal sacrifice.</p>",
"7": "<p><strong>ʾāz ʾāmartî hinnēh bāʾtî bimĕgillat-sēper kātûb ʿālay</strong> (<em>ʾāz ʾāmartî hinnēh ḇāʾṯî ḇimĕgillat-sēper kāṯûḇ ʿālay</em>): 'Then I said, 'Behold, I have come; in the scroll of the book it is written of me.'' The phrase hinnēh bāʾtî ('behold, I have come') is the response to the inadequacy of sacrifices: the psalmist comes in person, in obedience. The scroll (mĕgillat-sēper) contains what is kātûb ʿālay ('written about me') — a mysterious scroll that prescribes the speaker's role. Hebrews 10:7 applies this to Christ: 'Then I said, 'Behold, I have come to do your will, O God, as it is written of me in the scroll of the book.'' The scroll that prescribes Christ's obedience encompasses the entire OT witness to the Messiah — the Psalter's voice becomes the Messiah's self-declaration at the incarnation.</p>",
"8": "<p><strong>laʿăśôt rĕṣônĕkā ʾĕlōhay ḥāpaṣtî wĕtôrātĕkā bĕtôk mēʿāy</strong> (<em>laʿăśôṯ rĕṣôneḵā ʾĕlōhay ḥāp̄aṣtî wĕṯôrāṯeḵā bĕṯôḵ mēʿāy</em>): 'I delight to do your will, O my God; your law is within my heart.' The psalmist's (and in Heb 10, Christ's) self-description: laʿăśôt rĕṣônĕkā ḥāpaṣtî, 'to do your will I delight' — the ḥāpaṣ ('delight') that YHWH does not find in animal sacrifice (v.6) is found here, in the person who delights in obedience. The parallel: wĕtôrātĕkā bĕtôk mēʿāy, 'and your Torah is in my inner parts/bowels' — Torah internalized in the very viscera (mēʿayim), not merely studied. This is the Jeremianic new covenant (Jer 31:33) realized in the individual who offers obedience rather than animal blood. In Christ, this becomes the perfect incarnate obedience that accomplishes what no sacrifice could.</p>",
"9": "<p><strong>biśśartî ṣedeq bĕqāhāl rāb hinnēh śĕpātay lōʾ ʾeklaʾ YHWH ʾattâ yādāʿtā</strong> (<em>biśśarṯî ṣeḏeq bĕqāhāl rāḇ hinnēh śĕp̄āṯay lōʾ ʾeḵlāʾ YHWH ʾattâ yāḏāʿtā</em>): 'I have told the glad news of righteousness in the great congregation; behold, I have not restrained my lips, as you know, O LORD.' The verb bāśar (piel biśśartî, 'to bring good news, evangelize') — the root of bĕśôrâ ('good news, gospel') — makes the psalmist's public testimony explicitly an act of evangelism: the ṣedeq ('righteousness/vindication') is proclaimed as glad tidings to the qāhāl rāb ('the great assembly'). The witness is complete: lōʾ ʾeklaʾ śĕpātay ('I have not restrained my lips'). The LXX uses euēngelisamēn ('I evangelized') — the same word-group as NT euaggelion ('gospel').</p>",
"10": "<p><strong>lōʾ-kissîtî ṣidqātĕkā bĕtôk libbî ʾĕmûnātĕkā ûtĕšûʿātĕkā ʾāmartî lōʾ-kiḥadtî ḥasdĕkā waʾămittĕkā lĕqāhāl rāb</strong> (<em>lōʾ-kissîṯî ṣiḏqāṯeḵā bĕṯôḵ libbî ʾĕmûnāṯeḵā ûṯĕšûʿāṯeḵā ʾāmartî lōʾ-ḵiḥaḏtî ḥasdĕḵā waʾămiṯṯeḵā lĕqāhāl rāḇ</em>): 'I have not hidden your righteousness within my heart; I have spoken of your faithfulness and your salvation; I have not concealed your steadfast love and your faithfulness from the great assembly.' The five divine attributes publicly declared — ṣĕdāqâ ('righteousness'), ʾĕmûnâ ('faithfulness'), yĕšûʿâ ('salvation'), ḥesed ('steadfast love'), ʾĕmet ('truth/faithfulness') — are the content of the testimony. The double negation lōʾ kissîtî ... lōʾ kiḥadtî ('I have not hidden ... I have not concealed') frames the proclamation as total, leaving nothing of YHWH's character unexpressed. The lĕqāhāl rāb ('to the great assembly') makes the testimony fully public.</p>",
"11": "<p><strong>ʾattâ YHWH lōʾ-tiklaʾ raḥămêkā mimmennî ḥasdĕkā waʾămittĕkā tāmîd yiṣṣĕrûnî</strong> (<em>ʾattâ YHWH lōʾ-ṯiḵlāʾ raḥămeḵā mimmennî ḥasdĕḵā waʾămiṯṯeḵā ṯāmîd yiṣṣĕrûnî</em>): 'As for you, O LORD, you will not restrain your mercy from me; your steadfast love and your faithfulness will ever preserve me.' The transition: the psalmist declared God's character publicly (vv.9-10); now he prays that character toward himself. The verb kālaʾ ('restrain, hold back') — used in v.9 for the psalmist's non-restraint of lips — is now inverted in prayer: ʾattâ YHWH lōʾ-tiklaʾ raḥămêkā ('you, O LORD, do not restrain your mercies from me'). The dual guardians ḥasdĕkā waʾămittĕkā ('your steadfast love and your faithfulness') tāmîd yiṣṣĕrûnî ('always preserve me') — these divine attributes are the relentless pursuers of Ps 23:6's 'goodness and mercy shall follow me.'</p>",
"12": "<p><strong>kî ʾăpāpûnî rāʿôt ʿad-ʾên mispar tĕʾăzûqûnî ʿăwōnōtay wĕlōʾ-yākolltî lirʾôt ʿāṣĕmû miśśaʿărôt rōʾšî</strong> (<em>kî ʾăp̄āp̄ûnî rāʿôṯ ʿaḏ-ʾên mispar ṯĕʾăzûqûnî ʿăwōnōṯay wĕlōʾ-yāḵoltî lirʾôṯ ʿāṣĕmû miśśaʿărôṯ rōʾšî</em>): 'For evils have encompassed me beyond number; my iniquities have overtaken me, and I cannot see; they are more than the hairs of my head; my heart fails me.' The psalm pivots from praise (vv.1-11) to lament (vv.12-17). The evils (rāʿôt) that encompass (ʾāpap, 'surround, engulf') are ʿad-ʾên mispar ('without number'). The iniquities (ʿăwōnōt) that tĕʾăzûqûnî ('have overtaken, seized') — from ʾāzaq ('to seize') — are ʿāṣĕmû miśśaʿărôt rōʾšî, 'more than the hairs of my head.' The heart's failure — wĕlibî ʿăzābānî ('my heart has forsaken me') — returns to the language of Ps 38's bodily collapse. Vv.12-17 appear again in Psalm 70 as a standalone prayer for help, confirming its independent liturgical use.</p>",
"13": "<p><strong>rĕṣēh YHWH lĕhaṣṣîlēnî YHWH lĕʿezrātî ḥûšâ</strong> (<em>rĕṣēh YHWH lĕhaṣṣîlēnî YHWH lĕʿezrātî ḥûšâ</em>): 'Be pleased, O LORD, to deliver me! O LORD, make haste to help me!' The double imperative — rĕṣēh ('be pleased, be willing!') and ḥûšâ ('hurry!') — addresses both YHWH's will and his timing. The verb rāṣâ ('to be pleased with, accept favorably') asks YHWH to lĕhaṣṣîlēnî ('deliver me') — not from duty but from willing favor. The urgency ḥûšâ lĕʿezrātî, 'hurry to my help,' returns to Ps 38:22's identical closing. The phrase recurs in Ps 70:1 and shapes the ending of the Psalter's Daily Prayer tradition. In the liturgy it becomes the opening of the Hours of prayer (Deus in adiutorium meum intende).</p>",
"14": "<p><strong>yēbōšû wĕyaḥpĕrû yaḥdāw mĕbaqqĕšê napšî lispôtāh yissōgû ʾāḥôr wĕyikkālĕmû ḥăpēṣê rāʿātî</strong> (<em>yēḇōšû wĕyaḥp̄ĕrû yaḥḏāw mĕḇaqqĕšê napšî lisp̄ôṯāh yissōḡû ʾāḥôr wĕyikkālĕmû ḥăp̄ēṣê rāʿāṯî</em>): 'Let them be put to shame and disappointed altogether who seek to snatch away my life; let them be turned back and brought to dishonor who delight in my hurt.' The imprecatory jussives — yēbōšû ('let them be ashamed'), yaḥpĕrû ('let them be confounded'), yissōgû ʾāḥôr ('let them be turned back'), yikkālĕmû ('let them be disgraced') — cover both the inner shame and the outward retreat of enemies. The phrase mĕbaqqĕšê napšî lispôtāh, 'those who seek to snatch away my life/throat,' uses lispôt ('to sweep away, snatch') — the violence of consumption imagery. The parallel ḥăpēṣê rāʿātî ('those who delight in my harm') echoes Ps 35:26.</p>",
"15": "<p><strong>yāšōmmû ʿal-ʿēqeb buštatām hāʾōmĕrîm lî heʾāḥ heʾāḥ</strong> (<em>yāšōmmû ʿal-ʿēqeḇ buštatām hāʾōmĕrîm lî heʾāḥ heʾāḥ</em>): 'Let them be appalled because of their shame who say to me, 'Aha, Aha!'' The prayer yāšōmmû ('let them be desolate/appalled') — from šāmam ('to be astonished, desolate, horrified') — asks that the enemies' shame become the occasion for their own horror. The exclamation heʾāḥ heʾāḥ ('aha! aha!') — which the enemies cry at the psalmist's suffering (Ps 35:21 also) — will rebound on those who uttered it: their gloating becomes their own shame.</p>",
"16": "<p><strong>yāśîśû wĕyiśmĕḥû bĕkā kol-mĕbaqqĕšêkā yōʾmĕrû tāmîd yigdal YHWH ʾōhăbê tĕšûʿātekā</strong> (<em>yāśîśû wĕyiśmĕḥû ḇeḵā ḵol-mĕḇaqqĕšêḵā yōʾmĕrû ṯāmîd yiḡḏal YHWH ʾōhăḇê ṯĕšûʿāṯeḵā</em>): 'May all who seek you rejoice and be glad in you; may those who love your salvation say continually, 'Great is the LORD!'' The counter-prayer for the covenant community: yāśîśû wĕyiśmĕḥû ('let them rejoice and be glad') — the same verbs used of the hoped-for individual joy in Ps 40:9. The community of mĕbaqqĕšêkā ('those who seek you') and ʾōhăbê tĕšûʿātekā ('those who love your salvation') join in the permanent liturgy yigdal YHWH ('great is the LORD!'). The enemies say heʾāḥ (v.15); the community says yigdal YHWH — the contrasting communal speech defines the two assemblies.</p>",
"17": "<p><strong>waʾănî ʿānî wĕʾebyôn ʾădōnāy yaḥăšōb lî ʿezrātî ûmĕpalṭî ʾattâ ʾĕlōhay ʾal-tĕʾaḥar</strong> (<em>waʾănî ʿānî wĕʾeḇyôn ʾăḏōnāy yaḥăšōḇ lî ʿezrātî ûmĕp̄alṭî ʾattâ ʾĕlōhay ʾal-ṯĕʾaḥar</em>): 'As for me, I am poor and needy, but the Lord takes thought for me. You are my help and my deliverer; do not delay, O my God!' The final verse holds the entire psalm in miniature: the psalmist is ʿānî wĕʾebyôn ('poor and needy') — the Psalter's most vulnerable pair — yet ʾădōnāy yaḥăšōb lî, 'the Lord thinks of me / takes me into account.' The verb ḥāšab ('to think, plan, account') suggests divine deliberation and intention directed toward the psalmist: YHWH calculates for him. The self-designations — ʿezrātî ('my help') and mĕpalṭî ('my deliverer') — are the psalmist's titles for YHWH. The closing prayer ʾal-tĕʾaḥar ('do not delay!') from ʾāḥar ('to tarry') urgently requests what was already promised. The psalm ends with the believer's most characteristic posture: needy, known, and waiting.</p>"
}
}

def main():
    existing = load_comm('mkt-original', 'psalms')
    merge_comm(existing, PSALMS)
    save_comm('mkt-original', 'psalms', existing)
    total = sum(len(v) for v in PSALMS.values())
    print(f'Psalms 37-40 mkt-original written — {total} verses.')

if __name__ == '__main__': main()
